def verify(answer):
    valid = []
    for b in range(10, 1000):
        x = 1*b + 7  # 17 in base b
        y = 9*b + 7  # 97 in base b
        if y % x == 0:
            valid.append(b)
    total = sum(valid)
    try:
        return int(str(answer).strip()) == total
    except Exception:
        return False

def verify(answer):
    count = 0
    for x in range(-100, 101):
        for y in range(-100, 101):
            if 12*x**2 - x*y - 6*y**2 == 0:
                count += 1
    try:
        return int(str(answer).strip()) == count
    except Exception:
        return False

def verify(answer):
    count = 0
    for p in permutations([1, 2, 3, 4, 5, 6, 7, 8]):
        num = int(''.join(map(str, p)))
        if num % 22 == 0:
            count += 1
    try:
        return int(str(answer).strip()) == count - 2025
    except Exception:
        return False
